import React, {Component} from 'react';

const width = (100 / 5 - 2 * 1)

export default class Gallery extends Component {
    state = {}

    constructor(props) {
        super(props);

    }

    componentDidMount() {
        this.listener = document.addEventListener('keydown', (({key}) => key === 'Escape' ? this.setState({clicked: null}) : null))
        fetch('dat.json')
            .then(response => response.json())
            .then((dat) => this.setState({gallery: dat.gallery}))
    }

    componentWillUnmount() {
        document.removeEventListener('keydown', this.listener)
    }

    render() {
        console.log(this.state.clicked)
        if (!this.state.gallery) return null
        return (
            <div style= {{
                width: '99vw'
            }}>
                {this.state.gallery.map((e, i) => <div style={{
                    position: 'relative',
                    float: 'left',
                    width: '20%',
                    height: '20vw',
                    zIndex: this.state.clicked === i ? 100 : 3,
                    transitionDuration: '.7s',
                    transform: this.state.clicked !== i ? '' :
                        `translate(${40 - i % 5 * 20}vw, ${15 - Math.floor(i / 5) * 20}vw)` +
                        ' scale(2.5)'
                }}>
                    <div style={{
                        width: '95%',
                        height: '95%',
                        margin: '2.5%',
                        backgroundImage: `url(images/${e})`,
                        backgroundSize: 'cover',
                        backgroundPosition: 'center',
                        transitionDuration: '.3s',
                        transform: this.state.hovered === i && !this.state.clicked ? 'scale(1.01)' : 'scale(0.99)'
                    }}
                        onMouseEnter={() => this.setState({hovered: i})}
                        onMouseLeave={() => this.setState({hovered: null})}
                        onClick={() => this.setState({clicked: i, hovered: null})}
                    >
                    </div>
                </div>)}
            </div>
        )
    }
}
